#!/usr/bin/env python3
"""Regenerate ALIGNED mamba-GREEDY K=8 targets for the SAME 3600 XL prompts (contexts
already cached in real_context_dataset_xl.npz). The frozen SSM state encodes what MAMBA
would say next, so greedy self-continuation is the ALIGNED, stronger-signal STAGE-1 task
(n=251: 4.38x vs real-corpus 2.2x). Only the TARGETS change; contexts are reused verbatim.

Row i <-> meta['prompt_ids'][i] (npz row order == meta order). Produces greedy_targets_xl.npz
{greedy_target_ids:[N,8]} aligned to the npz rows. Crash-safe JSONL keyed by row index.

Run: python3 regen_greedy_targets.py [--workers 10]
"""
import argparse, json, os, sys, threading, time
import numpy as np, requests
from concurrent.futures import ThreadPoolExecutor

_HERE = os.path.dirname(os.path.abspath(__file__))
META = os.path.join(_HERE, "real_context_dataset_xl.meta.json")
OUT_NPZ = os.path.join(_HERE, "greedy_targets_xl.npz")
CACHE = os.path.join(
    "/private/tmp/claude-501/-Users-buley-Documents-Code-monorepo/"
    "dab2040a-b9df-4f6b-8f0f-d96780b01544/scratchpad", "greedy_targets_cache.jsonl")
URL = "https://mctx---gnosis-openai-mesh-6ptd7xm6fq-uc.a.run.app/debug/forward"
HDR = {"User-Agent": "Mozilla/5.0", "Content-Type": "application/json"}
K = 8


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--workers", type=int, default=10)
    args = ap.parse_args()
    meta = json.load(open(META))
    pids = meta["prompt_ids"]
    N = len(pids)
    print(f"[greedy] {N} prompts, K={K} greedy tokens each = {N*K} canary calls", flush=True)

    done = {}
    if os.path.exists(CACHE):
        for line in open(CACHE):
            try:
                r = json.loads(line); done[r["row"]] = r["greedy"]
            except Exception:
                pass
        print(f"[resume] {len(done)} rows already cached", flush=True)

    lock = threading.Lock()
    cnt = {"n": len(done), "fail": 0}
    cache = open(CACHE, "a")
    sess = requests.Session(); sess.headers.update(HDR)

    def forward(tokens):
        for attempt in range(18):
            try:
                r = sess.post(URL, json={"tokens": tokens, "return_context": False}, timeout=120)
                if r.status_code == 200:
                    return r.json()["argmax"]
                if r.status_code in (429, 503):
                    time.sleep(3 + attempt * 2)
                else:
                    time.sleep(1 + attempt)
            except Exception:
                time.sleep(3 + attempt * 2)
        return None

    def work(row):
        if row in done:
            return
        toks = list(pids[row])
        greedy = []
        for _ in range(K):
            a = forward(toks)
            if a is None:
                with lock:
                    cnt["fail"] += 1
                print(f"  [FAIL] row {row}", flush=True)
                return
            greedy.append(int(a)); toks.append(int(a))
        with lock:
            cache.write(json.dumps({"row": row, "greedy": greedy}) + "\n"); cache.flush()
            cnt["n"] += 1
            if cnt["n"] % 100 == 0:
                print(f"  [{cnt['n']}/{N}] cached (fail={cnt['fail']})", flush=True)

    t0 = time.time()
    with ThreadPoolExecutor(max_workers=args.workers) as ex:
        list(ex.map(work, range(N)))
    cache.close()
    print(f"[greedy] done: {cnt['n']} rows, {cnt['fail']} failed, {time.time()-t0:.0f}s", flush=True)

    # assemble aligned array
    rows = {}
    for line in open(CACHE):
        try:
            r = json.loads(line); rows[r["row"]] = r["greedy"]
        except Exception:
            pass
    got = sorted(rows.keys())
    arr = np.zeros((N, K), dtype=np.int64)
    miss = [i for i in range(N) if i not in rows]
    for i in range(N):
        arr[i] = rows[i] if i in rows else [0] * K
    np.savez_compressed(OUT_NPZ, greedy_target_ids=arr,
                        valid=np.array([i in rows for i in range(N)]))
    print(f"[greedy] assembled -> {OUT_NPZ}  ({len(got)}/{N} rows, {len(miss)} missing)", flush=True)


if __name__ == "__main__":
    main()
